import { randomUUID } from "node:crypto";
import { RecordId } from "surrealdb";
import { cosineSimilarity } from "./embeddings";
const SEARCH_KINDS = ["project", "feature", "task", "decision", "question", "suggestion"];
function toRecordIdString(record) {
  return record.id;
}
function toIsoString(value) {
  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
}
function normalizeSearchValue(value) {
  return value.trim().toLowerCase().replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ");
}
export function parseRecordIdString(value, allowedTables, fallbackTable) {
  const normalized = value.trim();
  if (normalized.length === 0) {
    throw new Error("record id is required");
  }
  const separatorIndex = normalized.indexOf(":");
  if (separatorIndex === -1) {
    if (!fallbackTable) {
      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
    }
    return new RecordId(fallbackTable, normalized);
  }
  const table = normalized.slice(0, separatorIndex);
  const id = normalized.slice(separatorIndex + 1);
  if (!allowedTables.includes(table)) {
